// (delete ≠ uninstall ≠ stop). It flips the warden member to “status="removed"“
// (+ intent “desired_state="offline"“) and dispatches NO warden command: it removes
// the
// machine from the ROSTER, it does not tear the warden daemon off the box (that is
// the “uninstall“ verb). Never a hard tombstone — the audit row + token “sub“
// attribution survive; the exec-token expires by TTL (HS256 is stateless). There is
// NO “teardown_command“ placeholder: DELETE does not command removal, so it never
// hands back an installer/uninstaller line. “machine_id“ is the machine's stable
// id (== the warden member's own id; renamed from the hostname-era “host“).
type MachineDeleteResultDTO struct {
	MachineId *string `json:"machine_id,omitempty"`
	MemberId  string  `json:"member_id"`
	Removed   *bool   `json:"removed,omitempty"`
}

// MachineOnboardDTO Onboard (register) a machine as a warden member (“POST /api/machines“).
//
// “display_name“ is the human label for the machine (REQUIRED — e.g. "Seth's MBP").
// The MACHINE IDENTITY is no longer a hand-typed “host“ string: every onboard
// mints a NEW warden member whose stable, server-minted id (“m-<uuid12>“) IS the
// machine id (the warden carries no self-binding — routing resolves it by get_member
// of that id; see “handle_onboard_machine“). The display name is stored as a
// MachineAlias overlay keyed by that machine id. “ttl_days“ overrides the exec-token
// lifetime (defaults to a sensible 90 days; capped server-side at
// “MAX_AGENT_TTL_SECS“).
type MachineOnboardDTO struct {
	DisplayName string `json:"display_name"`
	TtlDays     *int   `json:"ttl_days,omitempty"`
}

// MachineOnboardResultDTO The onboard result (“POST /api/machines“). “member_id“ is the warden
// member freshly created for this machine; “machine_id“ is the SAME value,
// surfaced under the machine-model name (the machine id == the warden member's own
// id — the binding key agents store in their “desired_machine_id“ column). “token“
// is
// the freshly minted exec-token (“scope="agent"“, “sub=member_id“); “expires_in“
// is its lifetime in seconds; “boot_command“ is the copy-paste line the operator
// runs ON that machine to install the warden (identity rides in the token's “sub“,
// not a templated machine id).
//
// “claim_code“ is a short-lived (“claim_expires_in“ = 600 s), single-use code the
// “boot_command“ embeds (“install.sh?code=“) instead of the exec-token; the served
// script redeems it via “POST /api/machines/claim“ for the real token.
type MachineOnboardResultDTO struct {
	BootCommand    string `json:"boot_command"`
	ClaimCode      string `json:"claim_code"`
	ClaimExpiresIn int    `json:"claim_expires_in"`
	ExpiresIn      int    `json:"expires_in"`
	MachineId      string `json:"machine_id"`
	MemberId       string `json:"member_id"`
	Token          string `json:"token"`
}

// MachineTeardownHereResultDTO The result of tearing a machine's warden down ON THE SERVER HOST in one click
// (“POST /api/machines/{machine_id}/teardown-here“).
//
// The symmetric inverse of “BootstrapResultDTO“: the server runs
// “<ocwarden> teardown“ (“launchctl bootout“ + remove the install artifacts)
// on ITS OWN host, then — ONLY when the daemon is confirmed torn down
// (“exit_code == 0“) — soft-deletes the warden member. “ok“ is
// “exit_code == 0“. A non-zero exit is NOT an HTTP error but it is NOT a
// soft-delete either: the member stays on the roster (“removed=false“) so a
// failed local teardown never orphans a live daemon from its registry row —
// “log“ (merged stdout+stderr) carries the reason. “removed“ reports whether
// the member row was soft-deleted (true iff “ok“).
type MachineTeardownHereResultDTO struct {
	ExitCode  int    `json:"exit_code"`
	Log       string `json:"log"`
	MachineId string `json:"machine_id"`
	Ok        bool   `json:"ok"`
	Removed   *bool  `json:"removed,omitempty"`
}

// MachineUninstallResultDTO The uninstall result (“POST /api/machines/{member_id}/uninstall“, T-IUD).
//
// UNINSTALL is the MACHINE-lifecycle verb: it writes the owner INTENT
// “desired_state="uninstall"“ so the server reconcile arm drives the single
// “uninstall“
// RPC down to the warden (which runs “ocwarden uninstall“ on its box); the warden
// confirms via a command_result receipt, and the fold then flips “desired_state“
// back to
// OFFLINE while KEEPING the record (re-installable). The machine row is NOT removed
// (contrast DELETE) — an uninstalled machine can be re-provisioned by a later onboard
// / bootstrap.
//
// “dispatched“ reports whether an uninstall RPC will be driven: TRUE when the
// warden is online (the reconcile arm will emit the command); FALSE when the warden
// is already offline (no live SSE downstream to receive it — the machine is treated
// as already uninstalled, “desired_state“ left OFFLINE, nothing to command).
// “machine_id“ is the machine's stable id (== the warden member's own id;
// renamed from the hostname-era “host“).
type MachineUninstallResultDTO struct {
	Dispatched *bool   `json:"dispatched,omitempty"`
	MachineId  *string `json:"machine_id,omitempty"`
	MemberId   string  `json:"member_id"`
}

// MachineUpgradeResultDTO The upgrade result (“POST /api/machines/{member_id}/upgrade“, T-5f01).
//
// UPGRADE is the owner's one-click "pull this machine current NOW": the server
// pushes the “update“ warden-command verb down the machine's live SSE
// downstream, and the warden reacts by kicking its EXISTING self-update
// reconcile immediately (download + verify-before-swap + atomic swap + exec-in-
// place — the T-c93d event-driven seam) instead of waiting out its poll
// backstop. Fire-and-forget: no desired_state is written and nothing durable
// changes — the self-update loop is already idempotent and the machine row's
// “bin_status“ flips to “current“ on the next heartbeat once the swap lands.
//
// “dispatched“ reports whether the command was actually enqueued: TRUE when
// the warden is online (live SSE downstream drains the frame), FALSE when it is
// offline (nothing to command — an offline warden self-reconciles on its next
// connect anyway). An older warden build that does not know the “update“ verb
// logs-and-skips the frame safely (unknown-rpc refusal, reader loop unharmed).
// “machine_id“ is the machine's stable id (== the warden member's own id).
type MachineUpgradeResultDTO struct {
	Dispatched *bool   `json:"dispatched,omitempty"`
	MachineId  *string `json:"machine_id,omitempty"`
	MemberId   string  `json:"member_id"`
}

// MarkChatReadDTO Mark a conversation read up to a watermark (“POST /api/chat/mark-read“).
//
// “peer“ is the OTHER participant in the conversation; “last_read_ts“ is the
// newest message ts the caller has read. The reader is ALWAYS the verified JWT
// “sub“ (never a client-supplied field) — anti-spoof, mirroring chat post. The
// stored watermark is monotonic (only ever advances).
type MarkChatReadDTO struct {
	LastReadTs *float64 `json:"last_read_ts,omitempty"`
	Peer       string   `json:"peer"`
}

