// TaskStepDTO One workflow node on the task timeline. Every row is one progress leaf (parallel items are separate rows sharing “parallel_group“). A parallel stage is CONSECUTIVE rows sharing a non-empty “parallel_group“ — submit_plan refuses (400) split groups, one-lane groups and gates inside a group, so stored plans always fold cleanly. “status“ is the closed set “pending“ | “in_progress“ | “waiting_owner“ | “done“ | “superseded“. “done“ and “superseded“ are the step's terminal states: “superseded“ (T-1aea) is stamped by submit_plan alone — a replan freezes a step whose latest bound reply card was already answered/expired as kept history (original order, ahead of the fresh plan) unless the fresh plan re-lists the node by name; a superseded row counts toward neither “progress_done“ nor “progress_total“, is never the current node, is not agent-reportable and cannot be re-armed; its “finished_ts“ is the freeze moment. Gate projection: “is_gate“ with an empty “reply_card_id“ is the ANNOUNCED (dashed) gate; a non-empty “reply_card_id“ is a step carrying a live reply card — an ARMED gate, or a plain step a “create_reply_card“ ask auto-bound to. “reply_card_id“ always points at the LATEST bound card and persists after the step finishes (the permanent approval mark).
type TaskStepDTO struct {
	Dod           *string  `json:"dod,omitempty"`
	FinishedTs    *float64 `json:"finished_ts,omitempty"`
	Id            string   `json:"id"`
	IsGate        *bool    `json:"is_gate,omitempty"`
	Name          *string  `json:"name,omitempty"`
	OrderIdx      int      `json:"order_idx"`
	ParallelGroup *string  `json:"parallel_group,omitempty"`
	ReplyCardId   *string  `json:"reply_card_id,omitempty"`

	// ReplyCardStatus Read-time join: the CURRENT status (``waiting`` | ``answered``) of the reply card bound to this step (``reply_card_id``); ``""`` when the step carries no card. Lets the task-embedded card (TaskReplyCard) decide AT MOUNT whether to load eagerly (waiting — the live ask / the H4 answered-awaiting-pickup transitional) or lazily (answered — collapsed one-line summary, fetch on expand) WITHOUT a per-card GET, and lets the board derive the H4 badge without the child round-trip. NOT stored — computed each read from the card's live status.
	ReplyCardStatus *string  `json:"reply_card_status,omitempty"`
	StartedTs       *float64 `json:"started_ts,omitempty"`
	Status          string   `json:"status"`
	TaskId          string   `json:"task_id"`
	WaitingReason   *string  `json:"waiting_reason,omitempty"`
}

// TaskStepStatusUpdateDTO Agent-reported step status (MCP “update_step_status“): “pending“ → “in_progress“ → “done“ — “waiting_owner“ is NOT agent-reportable on either side (a step enters it only by opening a reply card: open_gate / create_reply_card auto-bind, and leaves it only when that card is answered, where the server restores in_progress), so reporting “waiting_owner“ is a 400 and a move out of it is a 409; other illegal transitions are a 409. “superseded“ is likewise not the agent's lever: the server freezes a replaced answered-card step itself on submit_plan (T-1aea), so reporting “superseded“ is a 400 and no report moves a step out of it (409 — terminal).
type TaskStepStatusUpdateDTO struct {
	Status        string  `json:"status"`
	WaitingReason *string `json:"waiting_reason,omitempty"`
}

// TokenDTO Owner-scoped JWT issued by `/api/login` (the one token for REST/MCP/SSE).
//
// `expires_in` is the token lifetime in seconds (the client relogins before it
// lapses). `owner_id` echoes the `sub` the token is scoped to.
type TokenDTO struct {
	ExpiresIn int     `json:"expires_in"`
	OwnerId   string  `json:"owner_id"`
	Token     string  `json:"token"`
	TokenType *string `json:"token_type,omitempty"`
}

// UpgradeResultDTO Response of `POST /api/update/upgrade` (owner-gated). `status` names the
// outcome ("restarting" — the new binary is already verified and swapped
// in place; the process re-execs right after this response) and
// `target_version` the GitHub release tag being installed. The endpoint
// fires only on the owner's explicit click; the OPT-IN `updater_auto_update`
// setting runs the same verified body unattended in the background.
type UpgradeResultDTO struct {
	Status        string `json:"status"`
	TargetVersion string `json:"target_version"`
}

// VersionDTO Build identity: app version, git sha, and the MCP catalog hash (M1 §3.9).
//
// `version` is the single human-facing version identity: an OFFICIAL package
// (bin/release) is stamped with its GitHub Release tag; a self-build keeps the
// honest "0.0.0" (the UI then falls back to git_sha + git_time as the build
// label).
//
// `git_time` is the commit time of the running `git_sha` (strict ISO-8601), or
// None when unavailable (release tarball / no git).
//
// `update_available` drives the software-update card: the server periodically
// asks GitHub Releases (repo pkyosx/OffiCraft, anonymous) for the newest
// published release (cached, refreshed in the background — unreachable GitHub
// NEVER slows this probe) and reports honestly: True iff the newest admissible
// release tag is STRICTLY NEWER than the running `version` under semver
// ordering (`latest_version` then carries the tag); running >= latest reads
// False, and a version label that does not parse as semver on either side
// reads False (with a server-side log warning) — never a prompt. A
// self-build's "0.0.0" sorts below any published release and therefore
// still prompts. Prereleases are admitted only when the
// `updater_receive_beta` setting is on.
type VersionDTO struct {
	CatalogHash     string  `json:"catalog_hash"`
	GitSha          string  `json:"git_sha"`
	GitTime         *string `json:"git_time,omitempty"`
	LatestVersion   *string `json:"latest_version,omitempty"`
	UpdateAvailable *bool   `json:"update_available,omitempty"`
	Version         string  `json:"version"`
}

// WebhookCreateDTO Create one webhook endpoint on a member (M4 §1). `endpoint_id` is REQUIRED, immutable after creation, per-member-unique, and restricted to letters/digits/`_`/`-` (422 otherwise; 409 on a duplicate id). `purpose` is optional editable free text. The server mints the opaque `token` and returns it once on the WebhookEndpointDTO.
type WebhookCreateDTO struct {
	EndpointId string `json:"endpoint_id"`

	// Platform Verification preset for the public `/in` inlet. Omit or `generic` = current behaviour (URL token only). `slack`/`github` = the server applies that platform's preset: the Slack url_verification challenge handshake and X-Slack-Signature HMAC, or the GitHub X-Hub-Signature-256 HMAC. Immutable after creation.
	Platform *WebhookCreateDTOPlatform `json:"platform,omitempty"`
	Purpose  *string                   `json:"purpose,omitempty"`

	// SigningSecret Write-only shared secret for HMAC verification (accepted on create, NEVER echoed back). Slack: the Signing Secret from the app's Basic Information page. GitHub: the secret set when creating the webhook. REQUIRED when `platform` is `slack` or `github`; ignored for `generic`.
	SigningSecret *string `json:"signing_secret,omitempty"`
}

// WebhookCreateDTOPlatform Verification preset for the public `/in` inlet. Omit or `generic` = current behaviour (URL token only). `slack`/`github` = the server applies that platform's preset: the Slack url_verification challenge handshake and X-Slack-Signature HMAC, or the GitHub X-Hub-Signature-256 HMAC. Immutable after creation.
type WebhookCreateDTOPlatform string

// WebhookEndpointDTO API representation of one webhook_endpoint (M4 回呼端點, §1). Carries the durable fields the member-detail panel renders. The `token` is the opaque secret the public `/in` inlet identifies (member · endpoint · purpose) by; it rides THIS authenticated owner-facing wire ONLY so the panel can compose + copy the callback URL (the UI masks it visually; copy yields the full URL). It is NEVER on any public or agent-facing wire. `endpoint_id` is the user-chosen, per-member-unique, immutable address key; `purpose` is editable free text; `status` is the enabled/disabled revocation toggle.
type WebhookEndpointDTO struct {
	CreatedTs float64 `json:"created_ts"`

	// DeliveredCount How many `/in` payloads passed verification AND were delivered to the member as a chat event. Owner-facing observability only — the public `/in` response never reflects any counter.
	DeliveredCount *int `json:"delivered_count,omitempty"`

	// DroppedCount How many `/in` calls that resolved to this token were silently discarded (failed verification, endpoint disabled, member gone). Calls with an unknown token have no endpoint to count against and are excluded by construction.
	DroppedCount *int   `json:"dropped_count,omitempty"`
	EndpointId   string `json:"endpoint_id"`

	// HasSigningSecret Whether this endpoint has a signing secret configured. The secret itself is NEVER echoed on any wire — not even masked; only this boolean is exposed (stricter than the `token` field, which the owner-facing panel still receives).
	HasSigningSecret *bool `json:"has_signing_secret,omitempty"`

	// LastDropReason Coarse classification of the most recent silent drop: `sig_failed` (Slack/GitHub signature or timestamp verification failed), `disabled` (endpoint was disabled), or `member_gone` (the bound member no longer resolves). Empty string when nothing was ever dropped.
	LastDropReason *string `json:"last_drop_reason,omitempty"`

	// LastReceivedTs Epoch seconds of the LAST `/in` request that resolved to this token — delivered, dropped, or challenge/ping alike. 0.0 when the endpoint has never been called.
	LastReceivedTs *float64 `json:"last_received_ts,omitempty"`

	// Platform The endpoint's verification preset (`generic`, `slack`, or `github`), fixed at creation.
	Platform *WebhookEndpointDTOPlatform `json:"platform,omitempty"`
	Purpose  string                      `json:"purpose"`
	Status   string                      `json:"status"`
	Token    string                      `json:"token"`
}

// WebhookEndpointDTOPlatform The endpoint's verification preset (`generic`, `slack`, or `github`), fixed at creation.
type WebhookEndpointDTOPlatform string

// WebhookRequestLogDTO One row of a webhook endpoint's /in debug ring buffer (GET /api/members/{member_id}/webhooks/{endpoint_id}/requests, newest first, at most 5 rows kept per endpoint). Records EVERY request /in resolved to the endpoint's token, whatever the outcome: `delivered` (verified payload landed as a chat), `dropped:sig_failed` / `dropped:disabled` / `dropped:member_gone` (silent drops with their coarse reason), `challenge` (the Slack url_verification handshake), `ping` (a verified GitHub ping). An unknown token has no endpoint to log against, by construction. `headers` is the JSON-serialised request header map (truncated at 4 KiB); `body` is the raw payload text (truncated at 16 KiB); `truncated` marks that either was cut. Owner-only debug wire (requires=owner) - raw external payloads never ride any public or agent-facing surface, and the public /in response stays byte-identical regardless of logging.
type WebhookRequestLogDTO struct {
	Body      string  `json:"body"`
	Headers   string  `json:"headers"`
	Outcome   string  `json:"outcome"`
	Truncated bool    `json:"truncated"`
	Ts        float64 `json:"ts"`
}

// WebhookUpdateDTO Partial edit of a webhook endpoint (M4 §1). PATCH semantics — only supplied fields change. `status` flips the enabled/disabled revocation toggle (a value outside the set is a 422); `purpose` edits the description. `endpoint_id` is immutable and is NOT editable here.
type WebhookUpdateDTO struct {
	Purpose *string `json:"purpose,omitempty"`

	// SigningSecret Write-only. Supply to set or rotate the endpoint's signing secret (never echoed back). `platform` is immutable and cannot be changed here.
	SigningSecret *string `json:"signing_secret,omitempty"`
	Status        *string `json:"status,omitempty"`
}

// WorkerBootContextDTO The outsource worker's boot-context PREVIEW (GET /api/outsource-workers/{id}/boot-context, T-ba6b) — the worker twin of the member panel's /api/bootstrap preview. The server re-runs the SAME buildWorkerBootContext fold the spawn path uses (worker_context.md seed + identity + the bound task in full + the type manual), from the CURRENT DB rows. HONEST: this is what the boot context would look like NOW — not a verbatim record of the spawn-time text (the task/manual may have changed since; nothing is stored). Never carries a worker token.
type WorkerBootContextDTO struct {
	Context string `json:"context"`
}

